# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_uploaded_file(filename):
    # Define the uploads directory path
    uploads_dir = os.path.join(os.getcwd(), "uploads")
    
    # Prevent directory traversal attacks by using only the basename
    safe_filename = os.path.basename(filename)
    file_path = os.path.join(uploads_dir, safe_filename)
    
    if os.path.exists(file_path):
        try:
            os.remove(file_path)
            return True
        except Exception:
            return False
    else:
        return False

# Example usage:
if __name__ == "__main__":
    fname = input("Enter the filename to delete: ")
    if delete_uploaded_file(fname):
        print("File deleted successfully.")
    else:
        print("File not found or could not be deleted.")